import pytest
import csv, io
from <fixture> import hr_admin_client, seed_employees_with_ids

PII_FIELDS = ("email", "phone", "address")

def test_opt_out_flag_determines_pii_redaction_decision_table(
    hr_admin_client, seed_employees_with_ids
):
    opted_out_ids, active_ids = seed_employees_with_ids(
        opted_out=3, active=3
    )

    resp = hr_admin_client.get("/api/employees/export.csv")
    assert resp.status_code == 200

    rows = {r["id"]: r for r in csv.DictReader(io.StringIO(resp.text))}

    for eid in opted_out_ids:
        row = rows[eid]
        for field in PII_FIELDS:
            assert row[field] == "REDACTED", \
                f"opted-out emp {eid}: {field} must be REDACTED"

    for eid in active_ids:
        row = rows[eid]
        for field in PII_FIELDS:
            assert row[field] not in ("", "REDACTED"), \
                f"active emp {eid}: {field} must be real value"
